def read_input(path_or_dash, stdin_text="", file_text=None):
    if path_or_dash == "-":
        return stdin_text
    return file_text if file_text is not None else f"<read {path_or_dash}>"
print(read_input("-", stdin_text="hola"))
print(read_input("f.txt", file_text="data"))

def merge(defaults, file_cfg, env_cfg, flags):
    out = dict(defaults)
    for layer in (file_cfg, env_cfg, flags):
        for k, v in layer.items():
            if v is not None:
                out[k] = v
    return out
print(merge({"log": "INFO", "n": 1}, {"n": 2}, {"log": "DEBUG"}, {"log": None}))

def validate_config(cfg: dict) -> None:
    for key in ("log_level", "data_dir"):
        if key not in cfg or cfg[key] in (None, ""):
            raise ValueError(f"config incompleta: falta {key}")
validate_config({"log_level": "INFO", "data_dir": "/data"})
try:
    validate_config({"log_level": "INFO"})
except ValueError as e:
    print("err", e)
print("ok")

